def is_strictly_increasing(numbers):
    for i in range(len(numbers) - 1):
        if numbers[i] >= numbers[i + 1]:
            return False
    return True

from math import factorial

def calculate_factorials(numbers):
    return [factorial(num) for num in numbers]

def largest_product_of_three(nums):
    nums.sort()
    n = len(nums)
    return max(nums[0] * nums[1] * nums[n-1], nums[n-3] * nums[n-2] * nums[n-1])

def check_isogram(string: str) -> bool:
    cleaned_string = ''.join(char.lower() for char in string if char.isalpha())
    return len(cleaned_string) == len(set(cleaned_string))

def calculate_factorial(n):
    if n == 0:
        return 1
    else:
        return n * calculate_factorial(n - 1)

import math

def square_root_rounded(numbers):
