from typing import Dict

def merge_grades(dict1: Dict[str, int], dict2: Dict[str, int]) -> Dict[str, int]:
    merged = dict1.copy()
    for subject, grade in dict2.items():
        if subject in merged:
            merged[subject] += grade
        else:
            merged[subject] = grade
    return merged

